  ('elementary-64311456-moex-00548', 'elementary-64311456', 'elementary-64311456-moex-112-6989845d', 'sub-elementary-64311456-04', NULL, 'single_choice', 'Lowenberg與Dolgoff（1922）認為，對於權力不平等者應給予適當的不同待遇，此為：', '["自由自主原則", "差別平等原則", "最小傷害原則", "生活品質原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:10+00:00", "source_pdf_sha1": "13927e4759e3", "answer_pdf_sha1": "9f92f5035bc4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "502", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "社會行政"}'::jsonb, NULL),
